struct NeuralGate {
    weights: Vec<f64>,
    learning_rate: f64,
}

impl NeuralGate {
    fn train(&mut self, input: &[f64], target: f64, epochs: usize) {
        for _ in 0..epochs {
            let output = self.forward(input);
            let error = target - output;
            // Update weights using gradient descent
            for i in 0..self.weights.len() {
                self.weights[i] += self.learning_rate * error * input[i];
            }
        }
    }

    fn forward(&self, input: &[f64]) -> f64 {
        input.iter().zip(&self.weights).map(|(x, w)| x * w).sum::<f64>()
            .clamp(0.0, 1.0) // Sigmoid-like squashing
    }
}

// Example: Train a gate to approximate AND (input [1.0, 1.0] → output 1.0)
let mut and_gate = NeuralGate { weights: vec![0.1, 0.1], learning_rate: 0.01 };
and_gate.train(&[1.0, 1.0], 1.0, 10_000);

After training, the gate’s output for `[1.0, 1.0]` would ideally converge near `1.0`, while `[0.0, 0.0]` → `0.0`.
